+        skill_id,
+        project_path.as_deref(),
+        disclosure_level,
+        None,
+        None,
+        None,
+    ) {
+        if ctx.verbosity > 0 {
+            eprintln!("warning: failed to record skill usage: {err}");
+        }
+    }
